import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for Swish activation
swish_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

template<typename T>
__device__ T sigmoid(T x) {
    return 1.0f / (1.0f + expf(-x));
}

template<>
__device__ __half sigmoid(__half x) {
    float x_f = __half2float(x);
    float result = 1.0f / (1.0f + expf(-x_f));
    return __float2half(result);
}

template<typename T>
__global__ void swish_kernel(const T* x, T* out, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < size) {
        T sigmoid_val = sigmoid(x[idx]);
        out[idx] = x[idx] * sigmoid_val;
    }
}

torch::Tensor swish_cuda(torch::Tensor x) {
    auto size = x.numel();
    auto out = torch::empty_like(x);

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(x.scalar_type(), "swish_cuda", [&] {
        swish_kernel<scalar_t><<<num_blocks, block_size>>>(
            x.data_ptr<scalar_t>(), 
            out.data_ptr<scalar_t>(), 
            size
        );
    });

    return out;
}
"""

swish_cpp_source = "torch::Tensor swish_cuda(torch::Tensor x);"

# Compile the inline CUDA code for Swish activation
swish_module = load_inline(
    name="swish_activation",
    cpp_sources=swish_cpp_source,
    cuda_sources=swish_source,
    functions=["swish_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    with_cuda=True,
)

class ModelNew(nn.Module):
    """
    Optimized model that performs Swish activation using custom CUDA kernel.
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.swish_op = swish_module

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies Swish activation to the input tensor using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of any shape.

        Returns:
            torch.Tensor: Output tensor with Swish applied, same shape as input.
        """
        if x.is_cuda:
            return self.swish_op.swish_cuda(x)
        else:
            # Fallback to PyTorch implementation for CPU tensors
            return x * torch.sigmoid(x)

